// ── Career Ops Portal Scanner ─────────────────────────────────────────
// Fetches Greenhouse / Ashby / Lever APIs, deduplicates, title-filters.
// Returns { jobs: [...], count: N, date: 'YYYY-MM-DD' }

const portalsYaml = $('Get portals.yml').first().json.data;
const historyTsv  = $('Get scan-history').first().json.data;

// ── Parse scan history (dedup set) ────────────────────────────────────
const seen = new Set(
  (historyTsv || '').split('\n').slice(1)
    .map(l => l.split('\t')[0].trim())
    .filter(u => u.startsWith('http'))
);

// ── Parse tracked_companies from portals.yml ──────────────────────────
function parseCompanies(yaml) {
  const companies = [];
  let inSection = false;
  let cur = null;
  for (const line of yaml.split('\n')) {
    if (line.startsWith('tracked_companies:')) { inSection = true; continue; }
    if (inSection && /^\S/.test(line) && !line.startsWith('tracked_companies:')) inSection = false;
    if (!inSection) continue;
    const nm = line.match(/^  - name:\s*(.+)/);
    if (nm) {
      if (cur?.name && cur?.url) companies.push(cur);
      cur = { name: nm[1].trim().replace(/^['"]|['"]$/g, ''), url: '', enabled: true };
      continue;
    }
    if (!cur) continue;
    const cu = line.match(/^\s+careers_url:\s*(.+)/);
    if (cu) cur.url = cu[1].trim();
    if (line.match(/^\s+enabled:\s*false/)) cur.enabled = false;
  }
  if (cur?.name && cur?.url) companies.push(cur);
  return companies.filter(c => c.enabled !== false);
}

// ── ATS detection + slug extraction ───────────────────────────────────
const getAts  = url => url.includes('greenhouse.io') ? 'greenhouse' : url.includes('ashbyhq.com') ? 'ashby' : url.includes('lever.co') ? 'lever' : null;
const getSlug = (url, t) => ({
  greenhouse: url.match(/greenhouse\.io\/([^/?]+)/),
  ashby:      url.match(/ashbyhq\.com\/([^/?]+)/),
  lever:      url.match(/lever\.co\/([^/?]+)/),
}[t]?.[1] ?? null);

// ── Fetch jobs from one company ────────────────────────────────────────
async function fetchJobs(c) {
  const t = getAts(c.url);
  const s = getSlug(c.url, t);
  if (!t || !s) return [];
  try {
    if (t === 'greenhouse') {
      const r = await fetch(`https://boards-api.greenhouse.io/v1/boards/${s}/jobs`);
      if (!r.ok) return [];
      return ((await r.json()).jobs || [])
        .filter(j => j.absolute_url)
        .map(j => ({ title: j.title || '', url: j.absolute_url, company: c.name, location: j.location?.name || '', ats: 'greenhouse', portal: s }));
    }
    if (t === 'ashby') {
      const r = await fetch(`https://jobs.ashbyhq.com/api/non-user-facing/application/job-board/listing?jobBoardIdentifier=${s}`);
      if (!r.ok) return [];
      return ((await r.json()).jobs || [])
        .filter(j => j.jobUrl)
        .map(j => ({ title: j.title || '', url: j.jobUrl, company: c.name, location: j.location || '', ats: 'ashby', portal: s }));
    }
    if (t === 'lever') {
      const r = await fetch(`https://api.lever.co/v0/postings/${s}?mode=json`);
      if (!r.ok) return [];
      const d = await r.json();
      return (Array.isArray(d) ? d : [])
        .filter(j => j.hostedUrl)
        .map(j => ({ title: j.text || '', url: j.hostedUrl, company: c.name, location: j.categories?.location || '', ats: 'lever', portal: s }));
    }
  } catch { return []; }
  return [];
}

// ── Title filter (matches portals.yml positive list) ───────────────────
const TITLE_KW = [
  'innovation lab','innovation lead','innovation manager','lab manager','lab lead',
  'r&d','open innovation','applied research','ai transformation','ai adoption',
  'ai lead','ai program','ai innovation','applied ai','ai enablement','ai education',
  'ai trainer','learning innovation','learning design','learning & development','l&d',
  'education technology','edtech','training lead','curriculum',
  'program manager','programme manager','technical program','product owner',
  'innovation program','serious game','game-based','gamification','venture builder',
  'intrapreneurship','scrum master','agile coach','digital transformation',
  'lector','docent','ai coach','ai consultant','ai specialist',
];
const matchTitle = t => TITLE_KW.some(kw => t.toLowerCase().includes(kw));

// ── Fetch all companies (batched concurrency) ──────────────────────────
const companies = parseCompanies(portalsYaml).filter(c => getAts(c.url));
const BATCH = 10;
const allJobs = [];
for (let i = 0; i < companies.length; i += BATCH) {
  const batch = companies.slice(i, i + BATCH);
  const results = await Promise.allSettled(batch.map(fetchJobs));
  for (const r of results) if (r.status === 'fulfilled') allJobs.push(...r.value);
}

// ── Dedup + title filter ───────────────────────────────────────────────
const today = new Date().toISOString().split('T')[0];
const newJobs = allJobs.filter(j => j.url && !seen.has(j.url) && matchTitle(j.title));

return [{ json: { jobs: newJobs, count: newJobs.length, date: today, scanned: companies.length } }];

// Expand jobs array into individual items for split-batches
const { jobs, date } = $input.first().json;
return jobs.map(j => ({ json: { ...j, added: date } }));
